243→/// Flatten a param name with its path into a single Z3 variable name.
244→fn param_var_name(name: &str, path: &[String]) -> String {
245→    if path.is_empty() {
246→        name.to_owned()
247→    } else {
248→        format!("{}.{}", name, path.join("."))
249→    }
