318→fn convert_binop(
319→    vars: &mut VarTable,
320→    op: BinOpKind,
321→    left: &SymExpr,
322→    right: &SymExpr,
323→    hint_sort: Sort,
324→) -> Result<Z3Ast, SolverError> {
325→    match op {
326→        BinOpKind::And => {
327→            let l = to_z3_bool(vars, left)?;
328→            let r = to_z3_bool(vars, right)?;
329→            Ok(Z3Ast::Bool(Bool::and(&[&l, &r])))
330→        }
331→        BinOpKind::Or => {
332→            let l = to_z3_bool(vars, left)?;
333→            let r = to_z3_bool(vars, right)?;
334→            Ok(Z3Ast::Bool(Bool::or(&[&l, &r])))
335→        }
336→
337→        BinOpKind::Eq | BinOpKind::Ne | BinOpKind::Lt | BinOpKind::Le | BinOpKind::Gt
338→        | BinOpKind::Ge => {
339→            let operand_sort = infer_comparison_sort(left, right, hint_sort);
340→            convert_comparison(vars, op, left, right, operand_sort)
341→        }
342→
343→        BinOpKind::Add | BinOpKind::Sub | BinOpKind::Mul | BinOpKind::Div | BinOpKind::Mod => {
344→            let arith_sort = infer_arithmetic_sort(left, right, hint_sort);
345→            convert_arithmetic(vars, op, left, right, arith_sort)
346→        }
347→
348→        BinOpKind::BitwiseAnd | BinOpKind::BitwiseOr | BinOpKind::BitwiseXor
349→        | BinOpKind::Shl | BinOpKind::Shr | BinOpKind::BitClear => {
350→            Err(SolverError::Unsupported(format!(
351→                "bitwise operator {op:?} not yet supported in Z3 solver"
352→            )))
353→        }
354→
355→        BinOpKind::In | BinOpKind::InstanceOf => Err(SolverError::Unsupported(format!(
356→            "JS operator {op:?} not supported in Z3 solver"
357→        ))),
358→    }
359→}
