361→fn infer_comparison_sort(left: &SymExpr, right: &SymExpr, _hint: Sort) -> Sort {
362→    let l = infer_sort(left);
363→    let r = infer_sort(right);
364→    if l != Sort::Int {
365→        l
366→    } else if r != Sort::Int {
