                | BinOpKind::Ne
                | BinOpKind::Lt
                | BinOpKind::Le
                | BinOpKind::Gt
                | BinOpKind::Ge,
            left,
            right,
        } => {
            let l = infer_sort(left);
            let r = infer_sort(right);
