        Sort::Int => {
            let l = to_z3_int(vars, left)?;
            let r = to_z3_int(vars, right)?;
            Ok(Z3Ast::Bool(match op {
                BinOpKind::Eq => l.eq(&r),
                BinOpKind::Ne => l.eq(&r).not(),
                BinOpKind::Lt => l.lt(&r),

