    fn x_gt_10() -> SymExpr {
        SymExpr::BinOp {
            op: BinOpKind::Gt,
            left: Box::new(SymExpr::Param {
                name: "x".into(),
                path: vec![],
            }),
            right: Box::new(SymExpr::Const(ConstValue::Int(10))),
        }
    }

    fn x_lt_20() -> SymExpr {
        SymExpr::BinOp {
            op: BinOpKind::Lt,
