    #[test]
    fn string_includes_negated_unsat() {
        // s == "abc" AND NOT s.includes("b") — should be unsat since "abc" contains "b"
        let constraints = vec![
            SymExpr::BinOp {
                op: BinOpKind::Eq,
                left: Box::new(str_param("s")),
                right: Box::new(SymExpr::Const(ConstValue::Str("abc".into()))),
